package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testGetNullStringWhenNullStringIsNull() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class,
                QuoteMode.class, Character.class, Character.class, boolean.class, boolean.class, String.class,
                String.class, Object[].class, String[].class, boolean.class, boolean.class, boolean.class,
                boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(',', '"', null, null, null, false, true, "\r\n",
                null, (Object) null, (String[]) null, false, false, false, false, false, false);
        assertNull(format.getNullString());
    }

    @Test
    void testGetNullStringWhenNullStringIsSet() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class,
                QuoteMode.class, Character.class, Character.class, boolean.class, boolean.class, String.class,
                String.class, Object[].class, String[].class, boolean.class, boolean.class, boolean.class,
                boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(',', '"', null, null, null, false, true, "\r\n",
                "NULL", (Object) null, (String[]) null, false, false, false, false, false, false);
        assertEquals("NULL", format.getNullString());
    }

    @Test
    void testGetNullStringViaWithNullString() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("testNull");
        assertEquals("testNull", format.getNullString());
    }

    @Test
    void testGetNullStringOnPredefinedConstants() {
        assertNull(CSVFormat.DEFAULT.getNullString());
        assertEquals("\\N", CSVFormat.MYSQL.getNullString());
        assertEquals("", CSVFormat.POSTGRESQL_CSV.getNullString());
        assertEquals("\\N", CSVFormat.POSTGRESQL_TEXT.getNullString());
    }
}
